import numpy as np

def compute_choi(channel_func, dim):
    """Compute Choi matrix for a channel."""
    choi = np.zeros((dim**2, dim**2), dtype=complex)
    for i in range(dim):
        for j in range(dim):
            # Basis element |i><j|
            basis = np.zeros((dim, dim), dtype=complex)
            basis[i, j] = 1
            output = channel_func(basis)
            # Place in Choi matrix
            for k in range(dim):
                for l in range(dim):
                    choi[i*dim + k, j*dim + l] = output[k, l]
    return choi / dim

def verify_cptp(choi, dim):
    """Check if Choi matrix represents CPTP map."""
    # Check CP: positive semidefinite
    eigvals = np.linalg.eigvalsh(choi)
    is_cp = np.all(eigvals >= -1e-10)

    # Check TP: partial trace = I/d
    pt = np.zeros((dim, dim), dtype=complex)
    for i in range(dim):
        for j in range(dim):
            for k in range(dim):
                pt[i, j] += choi[i*dim + k, j*dim + k]
    is_tp = np.allclose(pt, np.eye(dim) / dim)

    return {'CP': is_cp, 'TP': is_tp, 'min_eigenvalue': min(eigvals)}

# Test: Depolarizing channel
def depol(rho, p=0.2):
    d = rho.shape[0]
    return (1-p) * rho + p * np.eye(d) / d

choi = compute_choi(lambda r: depol(r, 0.2), 2)
result = verify_cptp(choi, 2)
print(f"Depolarizing channel: CP={result['CP']}, TP={result['TP']}")
print(f"Choi matrix eigenvalues: {np.linalg.eigvalsh(choi)}")
